
create table if not exists public.quiz_questions (
  id uuid primary key default gen_random_uuid(),
  question_no int not null,
  section text not null check (section in ('framework','product','skills','process')),
  question text not null,
  options jsonb not null,
  created_at timestamptz default now()
);

grant select on public.quiz_questions to authenticated;
grant all on public.quiz_questions to service_role;

alter table public.quiz_questions enable row level security;

drop policy if exists "quiz_questions readable" on public.quiz_questions;
create policy "quiz_questions readable" on public.quiz_questions for select to authenticated using (true);

create table if not exists public.rep_quiz_progress (
  user_id uuid primary key references auth.users(id) on delete cascade,
  passed boolean not null default false,
  best_score int not null default 0,
  attempts int not null default 0,
  passed_at timestamptz,
  updated_at timestamptz default now()
);

grant select, insert, update on public.rep_quiz_progress to authenticated;
grant all on public.rep_quiz_progress to service_role;

alter table public.rep_quiz_progress enable row level security;

drop policy if exists "own quiz progress select" on public.rep_quiz_progress;
drop policy if exists "own quiz progress insert" on public.rep_quiz_progress;
drop policy if exists "own quiz progress update" on public.rep_quiz_progress;

create policy "own quiz progress select" on public.rep_quiz_progress for select to authenticated using (auth.uid() = user_id);
create policy "own quiz progress insert" on public.rep_quiz_progress for insert to authenticated with check (auth.uid() = user_id);
create policy "own quiz progress update" on public.rep_quiz_progress for update to authenticated using (auth.uid() = user_id) with check (auth.uid() = user_id);

delete from public.quiz_questions;

